    }

    public virtual async Task DeleteAllAsync(string? filterText = null, string? name = null, string? slug = null, string? shortDescription = null, string? description = null, string? thumbnailUrl = null, string? coverImageUrl = null, string? address = null, decimal? latitudeMin = null, decimal? latitudeMax = null, decimal? longitudedMin = null, decimal? longitudedMax = null, string? phoneNumber = null, string? email = null, string? website = null, string? openingHours = null, PriceRange? priceRange = null, string? googleMapUrl = null, PlaceStatus? status = null, int? viewCountMin = null, int? viewCountMax = null, int? favoriteCountMin = null, int? favoriteCountMax = null, int? reviewCountMin = null, int? reviewCountMax = null, decimal? ratingAveragedMin = null, decimal? ratingAveragedMax = null, int? ratingTotalMin = null, int? ratingTotalMax = null, bool? isFeatured = null, bool? isHot = null, bool? isVerified = null, string? seoTitle = null, string? seoDescription = null, string? seoKeywords = null, Guid? placeCategoryId = null, Guid? provinceId = null, Guid? wardId = null, CancellationToken cancellationToken = default)
    {
        var query = await GetQueryForNavigationPropertiesAsync();
        query = ApplyFilter(query, filterText, name, slug, shortDescription, description, thumbnailUrl, coverImageUrl, address, latitudeMin, latitudeMax, longitudedMin, longitudedMax, phoneNumber, email, website, openingHours, priceRange, googleMapUrl, status, viewCountMin, viewCountMax, favoriteCountMin, favoriteCountMax, reviewCountMin, reviewCountMax, ratingAveragedMin, ratingAveragedMax, ratingTotalMin, ratingTotalMax, isFeatured, isHot, isVerified, seoTitle, seoDescription, seoKeywords, placeCategoryId, provinceId, wardId);
        var ids = query.Select(x => x.Place.Id);
        await DeleteManyAsync(ids, cancellationToken: GetCancellationToken(cancellationToken));
    }

    public virtual async Task<PlaceWithNavigationProperties> GetWithNavigationPropertiesAsync(Guid id, CancellationToken cancellationToken = default)
    {
        var dbContext = await GetDbContextAsync();
        return (await GetDbSetAsync()).Where(b => b.Id == id).Select(place => new PlaceWithNavigationProperties { Place = place, PlaceCategory = dbContext.Set<PlaceCategory>().FirstOrDefault(c => c.Id == place.PlaceCategoryId), Province = dbContext.Set<Province>().FirstOrDefault(c => c.Id == place.ProvinceId), Ward = dbContext.Set<Ward>().FirstOrDefault(c => c.Id == place.WardId) }).FirstOrDefault();
    }

    public virtual async Task<List<PlaceWithNavigationProperties>> GetListWithNavigationPropertiesAsync(string? filterText = null, string? name = null, string? slug = null, string? shortDescription = null, string? description = null, string? thumbnailUrl = null, string? coverImageUrl = null, string? address = null, decimal? latitudeMin = null, decimal? latitudeMax = null, decimal? longitudedMin = null, decimal? longitudedMax = null, string? phoneNumber = null, string? email = null, string? website = null, string? openingHours = null, PriceRange? priceRange = null, string? googleMapUrl = null, PlaceStatus? status = null, int? viewCountMin = null, int? viewCountMax = null, int? favoriteCountMin = null, int? favoriteCountMax = null, int? reviewCountMin = null, int? reviewCountMax = null, decimal? ratingAveragedMin = null, decimal? ratingAveragedMax = null, int? ratingTotalMin = null, int? ratingTotalMax = null, bool? isFeatured = null, bool? isHot = null, bool? isVerified = null, string? seoTitle = null, string? seoDescription = null, string? seoKeywords = null, Guid? placeCategoryId = null, Guid? provinceId = null, Guid? wardId = null, string? sorting = null, int maxResultCount = int.MaxValue, int skipCount = 0, CancellationToken cancellationToken = default)
    {
        var query = await GetQueryForNavigationPropertiesAsync();
        query = ApplyFilter(query, filterText, name, slug, shortDescription, description, thumbnailUrl, coverImageUrl, address, latitudeMin, latitudeMax, longitudedMin, longitudedMax, phoneNumber, email, website, openingHours, priceRange, googleMapUrl, status, viewCountMin, viewCountMax, favoriteCountMin, favoriteCountMax, reviewCountMin, reviewCountMax, ratingAveragedMin, ratingAveragedMax, ratingTotalMin, ratingTotalMax, isFeatured, isHot, isVerified, seoTitle, seoDescription, seoKeywords, placeCategoryId, provinceId, wardId);
        query = query.OrderBy(string.IsNullOrWhiteSpace(sorting) ? PlaceConsts.GetDefaultSorting(true) : sorting);
        return await query.PageBy(skipCount, maxResultCount).ToListAsync(cancellationToken);
    }

    protected virtual async Task<IQueryable<PlaceWithNavigationProperties>> GetQueryForNavigationPropertiesAsync()
    {
        return from place in (await GetDbSetAsync())
               join placeCategory in (await GetDbContextAsync()).Set<PlaceCategory>() on place.PlaceCategoryId equals placeCategory.Id into placeCategories
               from placeCategory in placeCategories.DefaultIfEmpty()
               join province in (await GetDbContextAsync()).Set<Province>() on place.ProvinceId equals province.Id into provinces
               from province in provinces.DefaultIfEmpty()
               join ward in (await GetDbContextAsync()).Set<Ward>() on place.WardId equals ward.Id into wards
               from ward in wards.DefaultIfEmpty()
               select new PlaceWithNavigationProperties
               {
                   Place = place,
                   PlaceCategory = placeCategory,
                   Province = province,
                   Ward = ward
               };
    }

