(openingHours), e => e.Place.OpeningHours.Contains(openingHours)).WhereIf(priceRange.HasValue, e => e.Place.PriceRange == priceRange).WhereIf(!string.IsNullOrWhiteSpace(googleMapUrl), e => e.Place.GoogleMapUrl.Contains(googleMapUrl)).WhereIf(status.HasValue, e => e.Place.Status == status).WhereIf(viewCountMin.HasValue, e => e.Place.ViewCount >= viewCountMin!.Value).WhereIf(viewCountMax.HasValue, e => e.Place.ViewCount <= viewCountMax!.Value).WhereIf(favoriteCountMin.HasValue, e => e.Place.FavoriteCount >= favoriteCountMin!.Value).WhereIf(favoriteCountMax.HasValue, e => e.Place.FavoriteCount <= favoriteCountMax!.Value).WhereIf(reviewCountMin.HasValue, e => e.Place.ReviewCount >= reviewCountMin!.Value).WhereIf(reviewCountMax.HasValue, e => e.Place.ReviewCount <= reviewCountMax!.Value).WhereIf(ratingAveragedMin.HasValue, e => e.Place.RatingAveraged >= ratingAveragedMin!.Value).WhereIf(ratingAveragedMax.HasValue, e => e.Place.RatingAveraged <= ratingAveragedMax!.Value).WhereIf(ratingTotalMin.HasValue, e => e.Place.RatingTotal >= ratingTotalMin!.Value).WhereIf(ratingTotalMax.HasValue, e => e.Place.RatingTotal <= ratingTotalMax!.Value).WhereIf(isFeatured.HasValue, e => e.Place.IsFeatured == isFeatured).WhereIf(isHot.HasValue, e => e.Place.IsHot == isHot).WhereIf(isVerified.HasValue, e => e.Place.IsVerified == isVerified).WhereIf(!string.IsNullOrWhiteSpace(seoTitle), e => e.Place.SeoTitle.Contains(seoTitle)).WhereIf(!string.IsNullOrWhiteSpace(seoDescription), e => e.Place.SeoDescription.Contains(seoDescription)).WhereIf(!string.IsNullOrWhiteSpace(seoKeywords), e => e.Place.SeoKeywords.Contains(seoKeywords)).WhereIf(placeCategoryId != null && placeCategoryId != Guid.Empty, e => e.PlaceCategory != null && e.PlaceCategory.Id == placeCategoryId).WhereIf(provinceId != null && provinceId != Guid.Empty, e => e.Province != null && e.Province.Id == provinceId).WhereIf(wardId != null && wardId != Guid.Empty, e => e.Ward != null && e.Ward.Id == wardId);
